import { createClient } from "@/lib/supabase/server"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { ArrowDownCircle, ArrowUpCircle } from "lucide-react"

export async function RecentTransactions({ userId }: { userId: string }) {
  const supabase = await createClient()

  const { data: transactions } = await supabase
    .from("transactions")
    .select(`
      *,
      mutual_funds (fund_name, fund_code)
    `)
    .eq("investor_id", userId)
    .order("transaction_date", { ascending: false })
    .limit(5)

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat("en-IN", {
      style: "currency",
      currency: "INR",
      minimumFractionDigits: 0,
    }).format(value)
  }

  const formatDate = (date: string) => {
    return new Date(date).toLocaleDateString("en-IN", {
      year: "numeric",
      month: "short",
      day: "numeric",
    })
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case "completed":
        return "bg-green-100 text-green-800"
      case "pending":
        return "bg-yellow-100 text-yellow-800"
      case "failed":
        return "bg-red-100 text-red-800"
      default:
        return "bg-gray-100 text-gray-800"
    }
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Recent Transactions</CardTitle>
      </CardHeader>
      <CardContent>
        {transactions && transactions.length > 0 ? (
          <div className="space-y-4">
            {transactions.map((transaction) => (
              <div key={transaction.id} className="flex items-center justify-between rounded-lg border p-4">
                <div className="flex items-center gap-4">
                  <div
                    className={`rounded-full p-2 ${transaction.transaction_type === "buy" ? "bg-green-100" : "bg-red-100"}`}
                  >
                    {transaction.transaction_type === "buy" ? (
                      <ArrowDownCircle className="h-5 w-5 text-green-600" />
                    ) : (
                      <ArrowUpCircle className="h-5 w-5 text-red-600" />
                    )}
                  </div>
                  <div>
                    <p className="font-medium">{transaction.mutual_funds?.fund_name}</p>
                    <p className="text-sm text-gray-500">
                      {transaction.units} units @ {formatCurrency(Number(transaction.nav))}
                    </p>
                    <p className="text-xs text-gray-400">{formatDate(transaction.transaction_date)}</p>
                  </div>
                </div>
                <div className="text-right">
                  <p
                    className={`font-semibold ${transaction.transaction_type === "buy" ? "text-green-600" : "text-red-600"}`}
                  >
                    {transaction.transaction_type === "buy" ? "-" : "+"}
                    {formatCurrency(Number(transaction.amount))}
                  </p>
                  <Badge className={getStatusColor(transaction.status)}>{transaction.status}</Badge>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <p className="text-center text-gray-500">No transactions yet</p>
        )}
      </CardContent>
    </Card>
  )
}
