// Lightweight Supabase server shim for demo/local mode
// Provides a minimal `createClient()` that maps common `.from(...).select().eq().order().limit()`
// usage in the codebase to the `LocalDB` functions in `lib/local-storage/db.ts`.

import { LocalDB } from "@/lib/local-storage/db"

type Chain = {
  select: (sel?: string) => Chain
  eq: (field: string, value: any) => Chain
  order: (field: string, opts?: { ascending?: boolean }) => Chain
  limit: (n: number) => Chain
  then: (onfulfilled: (res: any) => any, onrejected?: (err: any) => any) => Promise<any>
}

function makeChain(table: string): Chain {
  const filters: { field: string; value: any }[] = []
  let _order: { field: string; ascending?: boolean } | null = null
  let _limit: number | null = null

  async function run() {
    // Resolve basic tables via LocalDB
    if (table === "transactions") {
      // If filtered by investor_id, use LocalDB.getTransactions
      const investorFilter = filters.find((f) => f.field === "investor_id")
      let rows = [] as any[]
      if (investorFilter) {
        rows = await LocalDB.getTransactions(investorFilter.value)
      } else {
        rows = await LocalDB.getAllTransactions()
      }

      // Attach mutual_funds lookup if needed
      const funds = await LocalDB.getFunds()
      const enriched = rows.map((r) => ({
        ...r,
        mutual_funds: funds.find((f) => f.id === r.fund_id) || null,
      }))

      // Order: map common 'transaction_date' to created_at/processed_at
      if (_order) {
        const key = _order.field === "transaction_date" ? "processed_at" : _order.field
        enriched.sort((a, b) => {
          const av = a[key] || a.created_at || ""
          const bv = b[key] || b.created_at || ""
          if (av === bv) return 0
          return _order!.ascending ? (av > bv ? 1 : -1) : av > bv ? -1 : 1
        })
      }

      return { data: _limit ? enriched.slice(0, _limit) : enriched }
    }

    if (table === "mutual_funds") {
      const funds = await LocalDB.getFunds()
      return { data: _limit ? funds.slice(0, _limit) : funds }
    }

    if (table === "investments") {
      const investorFilter = filters.find((f) => f.field === "investor_id")
      if (investorFilter) {
        const inv = await LocalDB.getInvestments(investorFilter.value)
        return { data: _limit ? inv.slice(0, _limit) : inv }
      }
      return { data: await LocalDB.getAllInvestments() }
    }

    if (table === "users") {
      return { data: await LocalDB.getAllUsers() }
    }

    // Unknown table -> empty
    return { data: [] }
  }

  const chain: any = {
    select() {
      return chain
    },
    eq(field: string, value: any) {
      filters.push({ field, value })
      return chain
    },
    order(field: string, opts?: { ascending?: boolean }) {
      _order = { field, ascending: opts?.ascending }
      return chain
    },
    limit(n: number) {
      _limit = n
      return chain
    },
    then(onfulfilled: any, onrejected?: any) {
      return run().then(onfulfilled, onrejected)
    },
  }

  return chain as Chain
}

export async function createClient() {
  return {
    from(table: string) {
      return makeChain(table)
    },
  }
}

export default createClient
